var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐야? 테스트 시간이 끝나기도 전에 전부 처치라고…? 그런 게 가능한 거였어?!","JPN":"え？　制限時間を大幅に残して倒すなんて……？　そんなのできるの！？","ENG":"What? She just defeated all of them before the timer ended... How is that even possible?!","TWN":"什麼鬼？考試時間都還沒結束就都消滅完啦…？這是有可能的嗎？！"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"와아! 완전 빠르고 정확했어! 이건 틀림없이 최소 A급 확정이야!","JPN":"わあ！　すごく早くて正確だった！　絶対A級以上だよ！","ENG":"Wow! You were so fast and accurate! I'm sure you also got a Grade A, at least!","TWN":"哇！快狠準欸！這絕對至少有A級吧！"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"시엘 마로니에 – 관리국 공인 카운터 등급 C","JPN":"シエル・マロニエ – 管理局公認カウンターランクC","ENG":"Ciel Marronier – Official Administration Counter Grade: C.","TWN":"希爾·麥洛尼爾 – 管理局認證制裁者等級C"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"응…?","JPN":"え……？","ENG":"Mm...?","TWN":"什麼…？"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"에에엥?!","JPN":"えええっ！？","ENG":"Whaaat?!","TWN":"怎麼會？！"},"stage":{"bg":"TRAINING","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"저기 잠깐만요. 이거 뭔가 잘못된 거 아녜요?","JPN":"ちょって待ってください。何か間違ってるんじゃないですか？","ENG":"Um, excuse me. I think there's something wrong with the results.","TWN":"等一下，是不是哪裡弄錯啦？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"분명 시엘은 시뮬레이터의 침식체들을 전부 처리했잖아요! 한 대도 안 맞고요!","JPN":"シエルちゃんはシミュレーターの侵食体を全部倒したんですよ？　たったの一度も被撃せずに！","ENG":"Ciel defeated all the C.O.s in the simulation! She wasn't even hit once!","TWN":"希爾不是把模擬器的侵蝕體都消滅了嗎！而且她完全沒有被打到欸！"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"TEST_NPC_ACADEMY_NULL","text":{"KOREA":"죄송하지만 저희는 평가 기준에 따라 시험을 진행할 뿐입니다. 기준에는 문제가 없었어요.","JPN":"申し訳ありません。ですが私たちは評価基準に従い試験を行っています。そして基準に問題はありませんでした。","ENG":"I'm sorry, but we have our own criteria for this assessment. There was no mistake made in the process.","TWN":"很抱歉，我們是根據鑑定標準進行考試的，標準沒有問題。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"TEST_NPC_ACADEMY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"에… 말도 안 돼…","JPN":"え……なんで……","ENG":"That's... impossible...","TWN":"喔…奇怪…"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"본인의 CRF란 것이 관리국이 바라는 기준에는 그리 대단치 못한 모양이구려.","JPN":"自分のCRFが管理局の求めるレベルに遠く及ばなかったようですね。","ENG":"It appears that my CRF is not up to the standards of the Administration.","TWN":"可能以管理局的標準來看，在下的CRF不算厲害。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"안 됐지만 어쩔 수 없네. 카운터에 대해 누구보다 잘 아는 기관에서 C급이라는데, 우리가 뭘 어쩌겠어?","JPN":"残念だけど、仕方ないわね。カウンターについて誰よりも知り尽くしている管理局がC級判定を出したんだから、私たちじゃ反論のしようもないわ。","ENG":"I guess there's nothing we can really do about it. After all, they know more about Counters than any of us, so if they say you're a Grade C, you must be one, right?","TWN":"那也只能接受囉？畢竟在制裁者界最具公信力的機關說你是C級，那我們還能說什麼？"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"일리가 있는 말이오. 규칙이 통하는 곳에서는 그 규칙을 따르는 것이 정도이니까.","JPN":"その通りです。ルールのあるところでは、そのルールに従うのが常ですから。","ENG":"Your logic makes sense. When one is in Rome, one must do as the Romans do.","TWN":"說的有道理，既然已經定好規則，那就該遵守規則。"},"stage":{"bg":"TRAINING","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"정말이야? 엘리트인 나이엘이 해내지 못한 걸 신입생이 해내다니…","JPN":"まじか？　エリートのナイエルにできなかったことを、新入生がやってのけるとは……","ENG":"Really? But even the elite Naielle wasn't able to do what the new kid did...","TWN":"真的假的？新生做到的事是連奈爾也做不到的欸…"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"그러고 보면 지난 모의전투훈련 때도, 결국 신입생이 졌지만 나이엘이 꽤나 고전했어.","JPN":"そういえばこの間の模擬訓練で、新入生が負けはしたけど、ナイエルも結構苦戦していたな。","ENG":"Come to think of it, although Naielle defeated the new kid in the simulation training, she did struggle during the match.","TWN":"現在回想起來，上次的模擬戰訓練新生雖然輸給奈爾，但奈爾打得很辛苦。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"심지어 나이엘은 A급 카운터로 인정 받았잖아.","JPN":"それに、ナイエルはA級カウンターって判定が出たんだろ？","ENG":"What's more is that Naielle's been recognized as a Grade A Counter.","TWN":"而且奈爾還獲得A級制裁者的認證欸！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"A급이 해내지 못한 걸 C급이 해낼 수 있다면… 우리도 할 수 있는 걸까?","JPN":"A級にできないことをC級がやってのけたってことは……俺たちにもまだ希望があるんじゃね？","ENG":"If a Grade C can do what a Grade A couldn't... then maybe we can do it too.","TWN":"要是 C級可以做到A級做不到的事…那我們也可以嗎？"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TAO_NPC_ACADEMY_NULL","text":{"KOREA":"하하, 다들 정말 순진하구나?","JPN":"はは、お前たち、本当にピュアなんだな。","ENG":"Haha, aren't you a couple of naive fellows?","TWN":"哈哈，你們還真是頭腦簡單呢。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"TAO_NPC_ACADEMY_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};